def extract_blocks():
    blocks=extract_range(213,222,'DAENERYS','CH23')
    left,right=blocks[73],blocks[74]
    assert left['text'].endswith('Lands of the Long') and right['text'].startswith('Summer,')
    left['text']+=' '+right['text']; left['end_page']=right['end_page']; del blocks[74]
    for i,b in enumerate(blocks,1): b['order']=i; b['id']=f"CH23-P{int(b['page']):03d}-{i:03d}"
    # Original raw orders 12, 21, 26, 86–88; after the merge at 74, the final group becomes 85–87.
    for b in blocks:
        if b['order'] in {12,21,26,85,86,87}:
            b['text']=f"[原文涉及明确未成年角色的性内容，此处不逐字复录。请参见源 PDF p.{b['page']} 中对应段落。]"
    return blocks

